#!/usr/bin/env node

const fs = require('node:fs');
const path = require('node:path');
const https = require('node:https');

const REPO = 'vancityAyush/ssh_script';

function getArtifactName() {
  const platform = process.platform;
  const arch = process.arch;

  if (platform === 'darwin' && arch === 'x64') return 'sshx-darwin-x86_64';
  if (platform === 'darwin' && arch === 'arm64') return 'sshx-darwin-aarch64';
  if (platform === 'linux' && arch === 'x64') return 'sshx-linux-x86_64';
  if (platform === 'linux' && arch === 'arm64') return 'sshx-linux-aarch64';
  if (platform === 'win32' && arch === 'x64') return 'sshx-windows-x86_64.exe';

  throw new Error(`Unsupported platform/arch: ${platform}/${arch}`);
}

function download(url, destination, redirects = 0) {
  if (redirects > 5) {
    throw new Error('Too many redirects while downloading binary');
  }

  return new Promise((resolve, reject) => {
    const req = https.get(
      url,
      {
        headers: {
          'User-Agent': 'sshx-npm-installer'
        }
      },
      (res) => {
        if (
          res.statusCode &&
          res.statusCode >= 300 &&
          res.statusCode < 400 &&
          res.headers.location
        ) {
          res.resume();
          resolve(download(res.headers.location, destination, redirects + 1));
          return;
        }

        if (res.statusCode !== 200) {
          reject(new Error(`Download failed: ${res.statusCode} ${res.statusMessage || ''}`.trim()));
          res.resume();
          return;
        }

        const file = fs.createWriteStream(destination, { mode: 0o755 });
        res.pipe(file);

        file.on('finish', () => {
          file.close(resolve);
        });

        file.on('error', (err) => {
          fs.unlink(destination, () => reject(err));
        });
      }
    );

    req.on('error', reject);
  });
}

async function main() {
  if (process.env.SSHX_SKIP_DOWNLOAD === '1') {
    console.log('[sshx] Skipping binary download because SSHX_SKIP_DOWNLOAD=1');
    return;
  }

  const packageJsonPath = path.join(__dirname, '..', 'package.json');
  const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, 'utf8'));
  const version = packageJson.version;
  const tag = `sshx-v${version}`;
  const artifact = getArtifactName();

  const targetDir = path.join(__dirname, '..', 'bin');
  const targetName = process.platform === 'win32' ? 'sshx.exe' : 'sshx';
  const targetPath = path.join(targetDir, targetName);
  const tempPath = `${targetPath}.tmp`;

  fs.mkdirSync(targetDir, { recursive: true });

  const url = `https://github.com/${REPO}/releases/download/${tag}/${artifact}`;
  console.log(`[sshx] Downloading ${artifact} from ${tag}`);

  await download(url, tempPath);
  fs.renameSync(tempPath, targetPath);

  if (process.platform !== 'win32') {
    fs.chmodSync(targetPath, 0o755);
  }

  console.log('[sshx] Binary installed');
}

main().catch((err) => {
  console.error(`[sshx] Install failed: ${err.message}`);
  process.exit(1);
});

